import datetime
from elasticsearch import Elasticsearch
from elasticsearch.helpers import bulk

class CentralizedPlatform:
    def __init__(self, host='localhost', port=9200, index_prefix='my_platform'):
        self.es = Elasticsearch([{'host': host, 'port': port, 'scheme': 'http'}])
        self.index_prefix = index_prefix
        self.log_index_name = f"{self.index_prefix}_logs"
        self.document_index_name = f"{self.index_prefix}_documents"

    def _create_index_if_not_exists(self, index_name, mappings=None):
        if not self.es.indices.exists(index=index_name):
            print(f"Creating index: {index_name}")
            self.es.indices.create(index=index_name, body={'mappings': mappings} if mappings else None)
        else:
            print(f"Index {index_name} already exists.")

    def setup_indices(self):
        # Mappings for logs
        log_mappings = {
            "properties": {
                "timestamp": {"type": "date"},
                "level": {"type": "keyword"},
                "message": {"type": "text"},
                "service": {"type": "keyword"},
                "data": {"type": "object"}
            }
        }
        self._create_index_if_not_exists(self.log_index_name, log_mappings)

        # Mappings for documents
        doc_mappings = {
            "properties": {
                "title": {"type": "text", "fields": {"keyword": {"type": "keyword"}}},
                "content": {"type": "text"},
                "tags": {"type": "keyword"},
                "author": {"type": "keyword"},
                "created_at": {"type": "date"}
            }
        }
        self._create_index_if_not_exists(self.document_index_name, doc_mappings)

    # --- Document Indexing and Search ---

    def index_document(self, doc_id, document):
        """
        Indexes a single document.
        Document should be a dictionary, e.g.,
        {
            "title": "My First Document",
            "content": "This is the content of my first document. It talks about various topics.",
            "tags": ["python", "elasticsearch", "search"],
            "author": "John Doe",
            "created_at": datetime.now()
        }
        """
        if "created_at" not in document:
            document["created_at"] = datetime.datetime.now()
        try:
            response = self.es.index(index=self.document_index_name, id=doc_id, document=document)
            print(f"Document {doc_id} indexed successfully: {response['result']}")
            return response
        except Exception as e:
            print(f"Error indexing document {doc_id}: {e}")
            return None

    def bulk_index_documents(self, documents):
        """
        Indexes multiple documents using bulk API.
        Documents should be a list of dictionaries, each with an '_id' key.
        Example:
        [
            {'_id': 'doc1', 'title': 'Doc 1', 'content': 'Content 1', 'tags': ['tag1']},
            {'_id': 'doc2', 'title': 'Doc 2', 'content': 'Content 2', 'tags': ['tag2']}
        ]
        """
        actions = [
            {
                "_index": self.document_index_name,
                "_id": doc.pop('_id'),
                "_source": doc
            }
            for doc in documents
        ]
        try:
            success, failed = bulk(self.es, actions)
            print(f"Bulk indexing complete. Success: {success}, Failed: {failed}")
            return success, failed
        except Exception as e:
            print(f"Error during bulk indexing: {e}")
            return 0, len(documents)

    def search_documents(self, query_string, fields=None, size=10, highlight=True):
        """
        Performs a full-text search on documents.
        :param query_string: The search query string.
        :param fields: List of fields to search in (e.g., ['title', 'content']). If None, searches all text fields.
        :param size: Number of results to return.
        :param highlight: Whether to include highlight snippets in results.
        """
        search_body = {
            "query": {
                "multi_match": {
                    "query": query_string,
                    "fields": fields if fields else ["title^3", "content", "tags"] # Boost title field
                }
            },
            "size": size
        }

        if highlight:
            search_body["highlight"] = {
                "fields": {
                    "content": {},
                    "title": {}
                },
                "pre_tags": ["<em>"],
                "post_tags": ["</em>"]
            }

        try:
            response = self.es.search(index=self.document_index_name, body=search_body)
            print(f"\nSearch results for '{query_string}':")
            for hit in response['hits']['hits']:
                print(f"  ID: {hit['_id']}, Score: {hit['_score']}")
                print(f"  Title: {hit['_source'].get('title')}")
                if highlight and 'highlight' in hit:
                    for field, snippets in hit['highlight'].items():
                        print(f"  Highlight ({field}): {'...'.join(snippets)}")
                print("-" * 20)
            return response['hits']['hits']
        except Exception as e:
            print(f"Error during document search: {e}")
            return []

    # --- Logging Features ---

    def log_message(self, level, message, service="default", data=None):
        """
        Logs a message to Elasticsearch.
        :param level: Log level (e.g., "INFO", "WARN", "ERROR", "DEBUG").
        :param message: The log message string.
        :param service: The service generating the log.
        :param data: Optional dictionary for additional structured data.
        """
        log_entry = {
            "timestamp": datetime.datetime.now(),
            "level": level.upper(),
            "message": message,
            "service": service,
            "data": data if data is not None else {}
        }
        try:
            response = self.es.index(index=self.log_index_name, document=log_entry)
            # print(f"Log entry added: {response['result']} - {level}: {message}")
            return response
        except Exception as e:
            print(f"Error logging message: {e}")
            return None

    def search_logs(self, query_string=None, level=None, service=None, start_time=None, end_time=None, size=10):
        """
        Searches logs with various filters.
        :param query_string: Full-text search query for log messages.
        :param level: Filter by log level (e.g., "ERROR").
        :param service: Filter by service name.
        :param start_time: datetime object for start of time range.
        :param end_time: datetime object for end of time range.
        :param size: Number of log entries to return.
        """
        must_queries = []
        filter_queries = []

        if query_string:
            must_queries.append({"match": {"message": query_string}})
        if level:
            filter_queries.append({"term": {"level.keyword": level.upper()}})
        if service:
            filter_queries.append({"term": {"service.keyword": service}})

        if start_time or end_time:
            range_query = {"range": {"timestamp": {}}}
            if start_time:
                range_query["range"]["timestamp"]["gte"] = start_time.isoformat()
            if end_time:
                range_query["range"]["timestamp"]["lte"] = end_time.isoformat()
            filter_queries.append(range_query)

        search_body = {
            "query": {
                "bool": {
                    "must": must_queries if must_queries else [{"match_all": {}}],
                    "filter": filter_queries
                }
            },
            "sort": [{"timestamp": {"order": "desc"}}],
            "size": size
        }

        try:
            response = self.es.search(index=self.log_index_name, body=search_body)
            print(f"\nLog search results (query='{query_string}', level='{level}', service='{service}'):")
            for hit in response['hits']['hits']:
                source = hit['_source']
                print(f"  [{source['timestamp']}] {source['level']} | {source['service']}: {source['message']}")
                if source['data']:
                    print(f"    Data: {source['data']}")
            return response['hits']['hits']
        except Exception as e:
            print(f"Error during log search: {e}")
            return []

    def aggregate_logs_by_level(self, interval="1h"):
        """
        Aggregates log counts by level over a time interval.
        :param interval: Time interval for date histogram (e.g., "1h", "1d", "1w").
        """
        agg_body = {
            "aggs": {
                "logs_over_time": {
                    "date_histogram": {
                        "field": "timestamp",
                        "fixed_interval": interval,
                        "min_doc_count": 0
                    },
                    "aggs": {
                        "logs_by_level": {
                            "terms": {
                                "field": "level.keyword"
                            }
                        }
                    }
                }
            },
            "size": 0 # We only want aggregations, not hits
        }
        try:
            response = self.es.search(index=self.log_index_name, body=agg_body)
            print(f"\nLog Aggregation by Level (Interval: {interval}):")
            buckets = response['aggregations']['logs_over_time']['buckets']
            for bucket in buckets:
                time_key = datetime.datetime.fromtimestamp(bucket['key'] / 1000).strftime('%Y-%m-%d %H:%M')
                print(f"  Time: {time_key} (Total Docs: {bucket['doc_count']})")
                for level_bucket in bucket['logs_by_level']['buckets']:
                    print(f"    - {level_bucket['key']}: {level_bucket['doc_count']} logs")
            return response['aggregations']
        except Exception as e:
            print(f"Error during log aggregation: {e}")
            return {}

    def check_connection(self):
        """Checks if the Elasticsearch connection is alive."""
        if self.es.ping():
            print("Successfully connected to Elasticsearch!")
            return True
        else:
            print("Could not connect to Elasticsearch.")
            return False

